// Set path to watchout-config.json (edit this path if needed)
msg.filename = msg.payload || '/data/projects/XYZ-Exit10/node-red/config/watchout-config.json';
return msg;

// Parse watchout-config.json
let cfg = {};
try {
    cfg = JSON.parse(msg.payload);
} catch(e) {
    node.warn('[Watchout] watchout-config.json parse error, using defaults: ' + e.message);
}
cfg.host        = cfg.host        || 'localhost';
cfg.port        = cfg.port        || 3019;
cfg.mappingFile = cfg.mappingFile || '/projects/XYZ-Exit10/node-red/data/timeline-mapping.json';
flow.set('watchout_config', cfg);
node.status({ fill: 'green', shape: 'dot', text: 'Config: ' + cfg.host + ':' + cfg.port });
// Feed filename forward to read mapping file
msg.filename = cfg.mappingFile;
return msg;

// Config file missing — create defaults
const defaultCfg = {
    host: 'localhost',
    port: 3019,
    mappingFile: '/projects/XYZ-Exit10/node-red/data/timeline-mapping.json'
};
flow.set('watchout_config', defaultCfg);
node.warn('[Watchout] watchout-config.json not found — writing defaults');
msg.filename = '/config/watchout-config.json';
msg.payload  = JSON.stringify(defaultCfg, null, 2);
return msg;

// After writing default config, continue to mapping read
const cfg = flow.get('watchout_config') || {};
msg.filename = cfg.mappingFile || '/projects/XYZ-Exit10/node-red/data/timeline-mapping.json';
return msg;

// Parse timeline-mapping.json
let mapping = {};
try {
    const raw = JSON.parse(msg.payload);
    mapping = raw.mapping || raw || {};
} catch(e) {
    node.warn('[Watchout] timeline-mapping.json parse error, starting empty: ' + e.message);
}
flow.set('watchout_mapping', mapping);
flow.set('watchout_pending', null);
const count = Object.keys(mapping).length;
node.status({ fill: 'green', shape: 'dot', text: 'Mapping loaded: ' + count + ' timelines' });
return null;

// Mapping file missing — start with empty mapping
flow.set('watchout_mapping', {});
flow.set('watchout_pending', null);
node.warn('[Watchout] timeline-mapping.json not found — starting with empty mapping');
return null;

// Only poll Watchout state when SSE is not connected (fallback mode)
if (flow.get('watchout_sse_status') === 'connected') {
    return null;
}

const cfg  = flow.get('watchout_config') || {};
const host = cfg.host || 'localhost';
const port = cfg.port || 3019;
msg.method  = 'GET';
msg.url     = 'http://' + host + ':' + port + '/v0/state';
msg.headers = { 'Content-Type': 'application/json' };
return msg;

// Handle the GET /v0/state poll response
const statusCode = msg.statusCode || 200;
if (statusCode !== 200) {
    node.warn('[Watchout Poll] HTTP ' + statusCode);
    return null;
}

const state = msg.payload;
flow.set('watchout_state', state);

// Pass downstream (and also preserve your existing wrapper shape)
msg.topic = 'watchout/state';
msg.payload = { type: 'poll', data: state };
return msg;

// Input can be:
// - msg.watchout_sse_status
// - msg.payload.status
// - or read from flow context
const raw =
  msg.watchout_sse_status ||
  msg.payload?.watchout_sse_status ||
  flow.get("watchout_sse_status");

let state = "disconnected";
if (raw === "connected") state = "connected";
else if (raw === "disconnected") state = "disconnected";
else if (raw === "error") state = "error";
else if (raw === "connecting") state = "connecting"; // if you add this in your flow

msg.payload = {
  state,
  label: "Watchout",
  layout: "row",
};

return msg;

// Validate input and build HTTP request for Watchout control.
// Output 1: valid command  → HTTP Request node
// Output 2: invalid command → error object (wire this to debug / ui toast)
//
// Expected input (msg.payload):
//   Timelines:
//     { command: "start"|"stop"|"pause", timelineId: "show_1" }
//     { command: "start"|"stop"|"pause", contentId:  "show_1" }  // legacy – backward compat
//     { command: "playAll" }
//     { command: "getState" }
//
//   Jump to Time:
//     { command: "jumpToTime", timelineId: "show_1", milliseconds: 12345, state?: "pause"|"play" }
//
//   Jump to Cue:
//     { command: "jumpToCue", timelineId: "show_1", cueId: "intro", state?: "pause"|"play" }
//
//   Get Timeline Cues:
//     { command: "getCues", timelineId: "show_1" }
//
//   Inputs (Watchout UI calls these "Variables"; HTTP API calls them "Inputs"):
//     { command: "setVar",  varName: "MyInput", varValue: 0.5 }
//     { command: "setVars", vars: [{key, value, duration?}, ...] }
//
//   Cue Group State (Cue Sets):
//     { command: "getCueGroupStatesById" }
//     { command: "getCueGroupStatesByName" }
//     { command: "setCueGroupVariantById", groupId: "1", variantId: "2" }
//     { command: "setCueGroupVariantByName", groupName: "Group A", variantName: "Variant 1" }
//     { command: "setCueGroupVariantsById", states: { "groupId1": "variantId1", "groupId2": "variantId2" } }
//     { command: "setCueGroupVariantsByName", states: { "groupName1": "variantName1", "groupName2": "variantName2" } }
//       - Reset all to defaults: { command: "setCueGroupVariantsByName", states: {} }

const cfg = flow.get('watchout_config') || {};
const host = cfg.host || 'localhost';
const port = cfg.port || 3019;
const baseUrl = 'http://' + host + ':' + port;

const input = msg.payload || {};
const command = input.command;

const mapping = flow.get('watchout_mapping') || {};

// Resolve a timelineId (or legacy contentId) to a numeric Watchout timeline ID.
// Accepts:
//   - A mapping key such as "show_1" → looks up mapping[key].watchoutId
//   - A raw numeric string / number such as "0" or 2 → used directly
// Mapping schema:
//   mapping[contentId] = { displayName: string, watchoutId: string }
function resolveTimelineInfo(rawId) {
    if (rawId === undefined || rawId === null) {
        return { timelineId: null, resolvedFrom: rawId, displayName: undefined };
    }

    if (Object.prototype.hasOwnProperty.call(mapping, rawId)) {
        const entry = mapping[rawId];

        // Defensive: allow old flat string mappings if they somehow still exist in memory
        if (typeof entry === 'string' || typeof entry === 'number') {
            return { timelineId: String(entry), resolvedFrom: rawId, displayName: undefined };
        }

        if (entry && typeof entry === 'object') {
            const timelineId = (entry.watchoutId !== undefined && entry.watchoutId !== null)
                ? String(entry.watchoutId)
                : null;

            const displayName = (entry.displayName !== undefined && entry.displayName !== null)
                ? String(entry.displayName)
                : undefined;

            return { timelineId, resolvedFrom: rawId, displayName };
        }

        // Entry exists but is malformed
        return { timelineId: null, resolvedFrom: rawId, displayName: undefined };
    }

    // Fallback: treat provided value as a raw timeline ID
    return { timelineId: String(rawId), resolvedFrom: rawId, displayName: undefined };
}

function badRequest(errorText) {
    const errMsg = {
        statusCode: 400,
        payload: {
            success: false,
            error: errorText
        }
    };
    return [null, errMsg];
}

// Resolve timelineId from message, supporting both new (timelineId) and
// legacy (contentId) field names for backward compatibility.
function getTimelineIdFromInput() {
    if (input.timelineId !== undefined && input.timelineId !== null && input.timelineId !== '') {
        return input.timelineId;
    }
    if (input.contentId !== undefined && input.contentId !== null && input.contentId !== '') {
        return input.contentId;
    }
    return undefined;
}

msg._command = command;
msg.headers = { 'Content-Type': 'application/json' };

switch (command) {
    // --------------------
    // Timelines
    // --------------------
    case 'playAll': {
        msg.method = 'POST';
        msg.url = baseUrl + '/v0/play';
        msg.payload = null;
        return [msg, null];
    }

    case 'start':
    case 'stop':
    case 'pause': {
        const rawId = getTimelineIdFromInput();
        if (rawId === undefined) {
            return badRequest('Missing payload.timelineId for command: ' + command);
        }

        const info = resolveTimelineInfo(rawId);
        if (!info.timelineId) {
            return badRequest('Unable to resolve timelineId for: ' + rawId);
        }

        // Timeline metadata for downstream formatter
        msg._timelineId = info.timelineId;
        msg._contentId = info.resolvedFrom;
        msg._displayName = info.displayName;

        msg.method = 'POST';

        const action = (command === 'start') ? 'play' : command; // start -> play
        msg.url = baseUrl + '/v0/' + action + '/' + encodeURIComponent(info.timelineId);

        msg.payload = null;
        return [msg, null];
    }

    // --------------------
    // Jump to Time
    // --------------------
    case 'jumpToTime': {
        const rawId = getTimelineIdFromInput();
        if (rawId === undefined) {
            return badRequest('Missing payload.timelineId for command: jumpToTime');
        }
        if (input.milliseconds === undefined || input.milliseconds === null) {
            return badRequest('Missing payload.milliseconds for command: jumpToTime');
        }

        const info = resolveTimelineInfo(rawId);
        if (!info.timelineId) {
            return badRequest('Unable to resolve timelineId for: ' + rawId);
        }

        msg._timelineId = info.timelineId;
        msg._contentId = info.resolvedFrom;
        msg._displayName = info.displayName;

        let qs = '?time=' + encodeURIComponent(String(input.milliseconds));
        if (input.state !== undefined && input.state !== null && input.state !== '') {
            qs += '&state=' + encodeURIComponent(String(input.state));
        }

        msg.method = 'POST';
        msg.url = baseUrl + '/v0/jump-to-time/' + encodeURIComponent(info.timelineId) + qs;
        msg.payload = null;
        return [msg, null];
    }

    // --------------------
    // Jump to Cue
    // --------------------
    case 'jumpToCue': {
        const rawId = getTimelineIdFromInput();
        if (rawId === undefined) {
            return badRequest('Missing payload.timelineId for command: jumpToCue');
        }
        if (input.cueId === undefined || input.cueId === null || input.cueId === '') {
            return badRequest('Missing payload.cueId for command: jumpToCue');
        }

        const info = resolveTimelineInfo(rawId);
        if (!info.timelineId) {
            return badRequest('Unable to resolve timelineId for: ' + rawId);
        }

        msg._timelineId = info.timelineId;
        msg._contentId = info.resolvedFrom;
        msg._displayName = info.displayName;
        msg._cueId = String(input.cueId);

        let qs = '';
        if (input.state !== undefined && input.state !== null && input.state !== '') {
            qs = '?state=' + encodeURIComponent(String(input.state));
        }

        msg.method = 'POST';
        msg.url = baseUrl + '/v0/jump-to-cue/' +
            encodeURIComponent(info.timelineId) + '/' +
            encodeURIComponent(String(input.cueId)) + qs;
        msg.payload = null;
        return [msg, null];
    }

    // --------------------
    // Get Timeline Cues
    // --------------------
    case 'getCues': {
        const rawId = getTimelineIdFromInput();
        if (rawId === undefined) {
            return badRequest('Missing payload.timelineId for command: getCues');
        }

        const info = resolveTimelineInfo(rawId);
        if (!info.timelineId) {
            return badRequest('Unable to resolve timelineId for: ' + rawId);
        }

        msg._timelineId = info.timelineId;
        msg._contentId = info.resolvedFrom;
        msg._displayName = info.displayName;

        msg.method = 'GET';
        msg.url = baseUrl + '/v0/cues/' + encodeURIComponent(info.timelineId);
        msg.payload = null;
        return [msg, null];
    }

    // --------------------
    // Inputs (Variables)
    // --------------------
    case 'setVar': {
        if (!input.varName) return badRequest('Missing payload.varName for command: setVar');
        if (input.varValue === undefined) return badRequest('Missing payload.varValue for command: setVar');

        msg.method = 'POST';
        msg.url = baseUrl + '/v0/input/' + encodeURIComponent(String(input.varName)) +
            '?value=' + encodeURIComponent(String(input.varValue));
        msg.payload = null;
        return [msg, null];
    }

    case 'setVars': {
        if (!Array.isArray(input.vars)) return badRequest('Missing payload.vars array for command: setVars');

        // Validate each item minimally
        for (let i = 0; i < input.vars.length; i++) {
            const v = input.vars[i];
            if (!v || typeof v !== 'object') return badRequest('setVars: vars[' + i + '] must be an object');
            if (!('key' in v)) return badRequest('setVars: vars[' + i + '] missing "key"');
            if (!('value' in v)) return badRequest('setVars: vars[' + i + '] missing "value"');
            // duration is optional
        }

        msg.method = 'POST';
        msg.url = baseUrl + '/v0/inputs';
        msg.payload = input.vars; // array of {key,value,duration?}
        return [msg, null];
    }

    case 'getState': {
        msg.method = 'GET';
        msg.url = baseUrl + '/v0/state';
        msg.payload = null;
        return [msg, null];
    }

    // --------------------
    // Cue Sets / Cue Group State
    // --------------------
    case 'getCueGroupStatesById': {
        msg.method = 'GET';
        msg.url = baseUrl + '/v0/cue-group-state/by-id';
        msg.payload = null;
        return [msg, null];
    }

    case 'getCueGroupStatesByName': {
        msg.method = 'GET';
        msg.url = baseUrl + '/v0/cue-group-state/by-name';
        msg.payload = null;
        return [msg, null];
    }

    case 'setCueGroupVariantById': {
        if (input.groupId === undefined || input.groupId === null || input.groupId === '') {
            return badRequest('Missing payload.groupId for command: setCueGroupVariantById');
        }
        if (input.variantId === undefined || input.variantId === null || input.variantId === '') {
            return badRequest('Missing payload.variantId for command: setCueGroupVariantById');
        }

        // Cue metadata for downstream formatter
        msg._groupId = String(input.groupId);
        msg._variantId = String(input.variantId);

        msg.method = 'POST';
        msg.url = baseUrl + '/v0/cue-group-state/by-id/' +
            encodeURIComponent(String(input.groupId)) + '/' +
            encodeURIComponent(String(input.variantId));
        msg.payload = null;
        return [msg, null];
    }

    case 'setCueGroupVariantByName': {
        if (!input.groupName) return badRequest('Missing payload.groupName for command: setCueGroupVariantByName');
        if (!input.variantName) return badRequest('Missing payload.variantName for command: setCueGroupVariantByName');

        // Cue metadata for downstream formatter
        msg._groupName = String(input.groupName);
        msg._variantName = String(input.variantName);

        msg.method = 'POST';
        msg.url = baseUrl + '/v0/cue-group-state/by-name/' +
            encodeURIComponent(String(input.groupName)) + '/' +
            encodeURIComponent(String(input.variantName));
        msg.payload = null;
        return [msg, null];
    }

    case 'setCueGroupVariantsById': {
        // states is an object: { "groupId1": "variantId1", ... }
        const states = ('states' in input) ? input.states : input.payload;
        if (states === undefined || states === null || typeof states !== 'object' || Array.isArray(states)) {
            return badRequest('Missing payload.states object for command: setCueGroupVariantsById');
        }

        // Cue metadata for downstream formatter
        msg._states = states;

        msg.method = 'POST';
        msg.url = baseUrl + '/v0/cue-group-state/by-id';
        msg.payload = states;
        return [msg, null];
    }

    case 'setCueGroupVariantsByName': {
        // states is an object: { "groupName1": "variantName1", ... } OR {} to reset to default
        const states = ('states' in input) ? input.states : input.payload;
        if (states === undefined || states === null || typeof states !== 'object' || Array.isArray(states)) {
            return badRequest('Missing payload.states object for command: setCueGroupVariantsByName');
        }

        // Cue metadata for downstream formatter
        msg._states = states;

        msg.method = 'POST';
        msg.url = baseUrl + '/v0/cue-group-state/by-name';
        msg.payload = states; // {} = reset all to default
        return [msg, null];
    }

    default: {
        return badRequest('Unknown command: ' + command);
    }
}

// Normalize the Watchout API response into a uniform JSON object

const statusCode = (msg.statusCode !== undefined && msg.statusCode !== null) ? msg.statusCode : 200;

// Fields set by "Prepare control request"
const command     = msg._command;

const timelineId  = msg._timelineId;
const contentId   = msg._contentId;
const displayName = msg._displayName;
const cueId       = msg._cueId;

// Cue group state fields (optional — set upstream if you want richer echo)
const groupId     = msg._groupId;
const variantId   = msg._variantId;
const groupName   = msg._groupName;
const variantName = msg._variantName;
const states      = msg._states;

// Build response object, omitting undefined fields
const out = {
    success:    statusCode < 300,
    command:    command,
    statusCode: statusCode,
    body:       msg.payload
};

if (timelineId !== undefined) out.timelineId = timelineId;
if (contentId !== undefined) out.contentId = contentId;
if (displayName !== undefined) out.displayName = displayName;
if (cueId !== undefined) out.cueId = cueId;

if (groupId !== undefined) out.groupId = groupId;
if (variantId !== undefined) out.variantId = variantId;
if (groupName !== undefined) out.groupName = groupName;
if (variantName !== undefined) out.variantName = variantName;
if (states !== undefined) out.states = states;

// Keep same behavior: payload is JSON string for HTTP Response node
msg.payload = JSON.stringify(out);

msg.statusCode = 200;
msg.headers = { 'Content-Type': 'application/json' };
return msg;

// Build ui-dropdown options from flow.watchout_mapping
// Show ONLY displayName in the dropdown, but keep value = the mapping key (contentId).

const mapping = flow.get('watchout_mapping') || {};

const keys = Object.keys(mapping);
keys.sort((a, b) => {
    const da = (mapping[a] && mapping[a].displayName) ? String(mapping[a].displayName) : String(a);
    const db = (mapping[b] && mapping[b].displayName) ? String(mapping[b].displayName) : String(b);
    return da.localeCompare(db);
});

const options = keys.map(key => {
    const entry = mapping[key] || {};
    const displayName = entry.displayName ? String(entry.displayName) : String(key);
    return { value: key, label: displayName };
});

// Preserve selection if possible
const current = flow.get('watchout_selected_timelineId');
let selected = current;
if (!selected || !Object.prototype.hasOwnProperty.call(mapping, selected)) {
    selected = options.length ? options[0].value : '';
}
flow.set('watchout_selected_timelineId', selected);

msg.options = options;
msg.payload = selected;

node.status({ fill: 'green', shape: 'dot', text: 'Options: ' + options.length });
return msg;

// Store selected timeline ID (mapping key / contentId) for use by UI buttons.
// Variable renamed from watchout_selected_contentId to watchout_selected_timelineId
// for consistency with the timelineId field in control messages.
flow.set('watchout_selected_timelineId', msg.payload);
return msg;

const command = msg.payload; // start|pause|stop
const timelineId = flow.get('watchout_selected_timelineId');

if (!timelineId) {
    node.status({ fill: 'red', shape: 'ring', text: 'No timeline selected' });
    return null;
}

msg.payload = { command, timelineId };
return msg;

// Adapter: GET /v0/state (poll) → UI payload for timelines list
// Output payload shape expected by the UI template:
//   { timelines: [{id,name,stateLabel,stateColor,timeText}], ts }

const state = (msg.payload && msg.payload.data) ? msg.payload.data : msg.payload;
const timelines = Array.isArray(state && state.timelines) ? state.timelines : [];

// Mapping schema: { contentId: { displayName, watchoutId } }
const mapping = flow.get('watchout_mapping') || {};

// Reverse lookup: watchoutId -> displayName
const idToName = {};
for (const contentId of Object.keys(mapping)) {
    const entry = mapping[contentId];
    if (entry && typeof entry === 'object' && entry.watchoutId != null) {
        idToName[String(entry.watchoutId)] = entry.displayName || contentId;
    }
}

// Derive run/pause/stop from poll fields
function deriveState(tl) {
    // Prefer NDJSON-style if it exists
    if (tl.playbackStatus) {
        const s = String(tl.playbackStatus).toLowerCase();
        if (s === 'run') return 'run';
        if (s === 'pause') return 'pause';
        return 'stop';
    }

    if (tl.running === true) return 'run';

    const tt = (tl.timelineTime !== undefined && tl.timelineTime !== null) ? Number(tl.timelineTime) : null;
    // Your requirement: running=false but timeline still "there" => treat as paused
    if (tl.running === false && tt !== null && !Number.isNaN(tt) && tt > 0) return 'pause';

    return 'stop';
}

function formatMmSs(ms) {
    if (ms === undefined || ms === null) return '--:--';
    const n = Number(ms);
    if (Number.isNaN(n) || n < 0) return '--:--';
    const totalSeconds = Math.floor(n / 1000);
    const mm = Math.floor(totalSeconds / 60);
    const ss = totalSeconds % 60;
    return String(mm).padStart(2, '0') + ':' + String(ss).padStart(2, '0');
}

function stateMeta(state) {
    if (state === 'run')  return { stateLabel: 'Running', stateColor: '#4caf50' }; // green
    if (state === 'pause') return { stateLabel: 'Paused',  stateColor: '#ffeb3b' }; // yellow
    return { stateLabel: 'Stopped', stateColor: '#9e9e9e' };
}

const items = timelines.map(tl => {
    const id = String(tl.id);
    const state = deriveState(tl);
    const meta = stateMeta(state);

    return {
        id,
        name: tl.name || idToName[id] || ('Timeline ' + id),
        state,                 // run|pause|stop (internal)
        stateLabel: meta.stateLabel,
        stateColor: meta.stateColor,
        timeText: formatMmSs(tl.timelineTime)
    };
});

// Show only Running + Paused (hide stopped)
const visible = items.filter(t => t.state === 'run' || t.state === 'pause');

msg.topic = 'watchout/timelines';
msg.payload = {
    timelines: visible,
    ts: new Date().toISOString()
};

return msg;

// Build the HTTP GET request for /v0/timelines
const cfg  = flow.get('watchout_config') || {};
const host = cfg.host || 'localhost';
const port = cfg.port || 3019;
msg.method  = 'GET';
msg.url     = 'http://' + host + ':' + port + '/v0/timelines';
msg.headers = { 'Content-Type': 'application/json' };
return msg;

// Prepare mapping JSON for file write
const pending = flow.get('watchout_pending');
if (!pending) {
    node.send({ payload: { status: 'nothing_pending' }, topic: 'watchout/confirm' });
    return null;
}

flow.set('watchout_mapping', pending);
flow.set('watchout_pending', null);

const cfg = flow.get('watchout_config') || {};
const savedAt = new Date().toISOString();

msg.filename = cfg.mappingFile || '/data/projects/XYZ-Exit10/node-red/data/timeline-mapping.json';
msg.payload  = JSON.stringify({ mapping: pending, lastSaved: savedAt }, null, 2);
msg._pendingMapping = pending;
msg._savedAt = savedAt;
return msg;

// Confirm & Save completed
const mapping = msg._pendingMapping || flow.get('watchout_mapping') || {};
node.status({ fill: 'green', shape: 'dot', text: 'Saved: ' + Object.keys(mapping).length + ' timelines' });
node.send({
    payload: {
        status:  'saved',
        mapping: mapping,
        savedAt: msg._savedAt || new Date().toISOString()
    },
    topic: 'watchout/confirm'
});
return null;

// Cancel pending discovery
flow.set('watchout_pending', null);
node.send({ payload: { status: 'cancelled' }, topic: 'watchout/cancel' });
return null;

// Parse GET /v0/timelines response and build diff

if (msg.statusCode !== 200) {
    msg.payload = { status: 'error', error: 'Watchout returned HTTP ' + (msg.statusCode || 'unknown') };
    return msg;
}

function parseTimelineName(name) {
    if (!name || name.startsWith('_')) return null;
    return name.trim().toLowerCase().replace(/\s+/g, '_').replace(/[^a-z0-9_]/g, '');
}

function compareMapping(oldMap, newMap) {
    const oldKeys = Object.keys(oldMap);
    const newKeys = Object.keys(newMap);
    return {
        removed: oldKeys.filter(k => !(k in newMap)),
        added: newKeys.filter(k => !(k in oldMap)),
        unchanged: oldKeys.filter(k => (k in newMap) && String(oldMap[k]?.watchoutId) === String(newMap[k]?.watchoutId)),
        changed: oldKeys.filter(k => (k in newMap) && String(oldMap[k]?.watchoutId) !== String(newMap[k]?.watchoutId)),
    };
}

function formatDiff(diff) {
    const lines = [];
    diff.removed.forEach(n => lines.push("REMOVED  : Timeline '" + n + "' no longer exists"));
    diff.added.forEach(n => lines.push("ADDED    : New timeline '" + n + "' discovered"));
    diff.changed.forEach(n => lines.push("CHANGED  : Timeline '" + n + "' ID has changed"));
    diff.unchanged.forEach(n => lines.push("OK       : '" + n + "'"));
    return lines;
}

const timelines = Array.isArray(msg.payload) ? msg.payload : [];

const newMapping = {};
timelines.forEach(tl => {
    const contentId = parseTimelineName(tl.name);
    if (!contentId) return;

    newMapping[contentId] = {
        displayName: tl.name,
        watchoutId: String(tl.id)
    };
});

const storedMapping = flow.get('watchout_mapping') || {};
const diff = compareMapping(storedMapping, newMapping);
const diffLines = formatDiff(diff);

flow.set('watchout_pending', newMapping);

const count = Object.keys(newMapping).length;
node.status({ fill: 'green', shape: 'dot', text: 'Discovered: ' + count + ' timelines' });

msg.payload = { status: 'discovered', count, diffLines, newMapping, diff };
return msg;
